import { ref, onMounted } from 'vue';
import StatsCard from '../components/StatsCard.vue';
import QuoteCard from '../components/QuoteCard.vue';
export default {
  name: 'DashboardView',
  components: {
    StatsCard,
    QuoteCard
  },
  setup() {
    const loading = ref(true);
    const error = ref(null);
    const recentQuotes = ref([]);
    const stats = ref({
      total: 0,
      pending: 0,
      validated: 0,
      expired: 0
    });
    const loadStats = async () => {
      try {
        // Simulated data for stats
        stats.value = {
          total: 100,
          pending: 20,
          validated: 70,
          expired: 10
        };
      } catch (e) {
        console.error('Error loading stats:', e);
      }
    };
    const loadRecentQuotes = async () => {
      try {
        loading.value = true;
        error.value = null;

        // Simulated data for recent quotes
        recentQuotes.value = [{
          id: 1,
          quote_number: 'Q12345',
          status: 'pending'
        }, {
          id: 2,
          quote_number: 'Q12346',
          status: 'validated'
        }, {
          id: 3,
          quote_number: 'Q12347',
          status: 'expired'
        }];
      } catch (e) {
        error.value = e.message;
      } finally {
        loading.value = false;
      }
    };
    onMounted(async () => {
      await Promise.all([loadStats(), loadRecentQuotes()]);
    });
    return {
      loading,
      error,
      recentQuotes,
      stats
    };
  }
};
